+static int
+check_xucred(const struct xucred *xucred, socklen_t len)
+{
+	if (len != sizeof(*xucred)) {
+		logmsgx("option value size %zu != %zu (sizeof(struct xucred))",
+		    (size_t)len, sizeof(*xucred));
+		return (-1);
